var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"바리케이드가 돌파당했습니다! 저희 장비만으로는 역부족입니다!","JPN":"バリケードが突破されました！　我々の装備だけでは力不足です！","ENG":"The barricade has been breached! We can't stop her with our equipment!","TWN":"路障被衝破了！ 光憑我們的裝備根本不夠！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SHOTGUN_TIDE_NULL_NULL","text":{"KOREA":"형님! 강소영 경위와 이유미 경정이 저희보다 먼저 뒤쫓아갔습니다!","JPN":"兄貴！　マエカワ警部補とカスカベ警視が私たちより先に追いかけていきました！","ENG":"Sir! Lieutenant Kang and Major Lee are already on her tail!","TWN":"大哥！姜素英警衛和李悠美警政，比我們早一步追上去了！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHOTGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DRONE_TIDE_NULL_NULL","text":{"KOREA":"용의자 발견. 제철소로 진입하는 모습이 카메라에 촬영되었습니다.","JPN":"容疑者を発見。製鉄所に入る姿が撮影されました。","ENG":"Suspect sighted. There's camera footage of her entering the steel mill.","TWN":"發現嫌犯，鏡頭有拍到進去鐵工廠的身影。"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"DRONE_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"좋아! 다들 두 사람을 도우러 간다!","JPN":"よし！　全員二人の応援に当たるぞ！","ENG":"Great! Let's go help the two police officers!","TWN":"很好！全都去幫她們兩個！"},"stage":{"bg":"SKYLINE_NIGHT","slots":{"L":null,"C":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"꺄악……!","JPN":"きゃっ……！","ENG":"Eeek…!","TWN":"啊啊……！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"경정님, 일어설 수 있겠어요?!","JPN":"警視様、立てそうですか？","ENG":"Major, think can you get up?","TWN":"警政大人，你站得起來嗎？！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그보다 방금 장외 홈런 맞은 야구공처럼 날아오시던데요?","JPN":"まるで場外ホームランの野球ボールみたいに飛んで来ましたね！","ENG":"By the way, you just got hurled across the room like a baseball.","TWN":"不過，你剛剛整個就像被擊出場外全壘打的棒球一樣，飛得好高好遠喔！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"누가 야구공이야! 근무 시간에 야구나 보고 있으니까 그런 소리가 나오지!","JPN":"誰が野球ボールよ！　勤務時間に野球試合ばかり見てるからそんなくだらない話に例えるのよ！","ENG":"I'm no baseball! This is all because you never stop watching those baseball videos, even when you're on duty!","TWN":"誰是棒球啦！你是不是上班時間都在偷看棒球，開口閉口就是棒球！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신은 제가 만난 경찰 중에서도 유달리 끈질기군요. 젊음의 힘입니까.","JPN":"私がこれまで経験した警察の中でも、あなたは特にしつこいですね。これが若さということでしょうか。","ENG":"You're more tenacious than any other police officer I've encountered. Is it perhaps thanks to your youthful vigor?","TWN":"你在我遇過的警察中算是特別有毅力的，這是年輕的本事嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"계속 방해하려 하신다면…… 저도 이제 타박상 수준에서 그치지 않겠습니다.","JPN":"邪魔し続けるなら……私も打撲傷程度の攻撃で終わりません。","ENG":"If you insist on interfering, however… I'll have to leave you more than bruises.","TWN":"但如果你再妨礙我……可能就不會只是一般的跌打損傷了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"손가락 하나 못 움직이게 <color=#ffd34c>결박 플레이</color>해 드리죠.","JPN":"指一本動かせない<color=#ffd34c>束縛プレイ</color>を披露しましょう。","ENG":"I'll leave you in <color=#ffd34c>bondage</color> so you couldn't even lift a finger.","TWN":"我會和你玩<color=#ffd34c>綑綁遊戲</color>，讓你連一根手指也動不了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"제 뒤로 오세요, 경정님!","JPN":"私の後ろへ、警視様！","ENG":"Get behind me, Major!","TWN":"警政大人，快躲到我後面！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"저리 비켜……! 무능력자 주제에 어쩌려고!","JPN":"退いて……！　無能力者のくせにどうするつもりなの！","ENG":"Step aside! What's an incompetent like you going to do?!","TWN":"你走開啦…！那麼沒用，躲你後面要幹嘛！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"알아요! 하지만 경정님을 묶어놔도 되는 건 저뿐이니까요!","JPN":"わかってます！　でも警視様を束縛していいのは私だけですから！","ENG":"I know! But I'm the only one who gets to tie you up!","TWN":"我知道！但是只有我可以把警政大人綁起來！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"이런 상황에 농담이 나와, 강소영 경위?!","JPN":"こんな状況でよくそんな冗談が言えるわね！？","ENG":"Now's not the time for dirty jokes, Lieutenant!","TWN":"姜素英警衛，這種時候你還有心情開玩笑？！"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};